   171|
   172|export async function handleIVXOwnerPasswordlessLogin(request: Request): Promise<Response> {
   173|  if (request.method !== 'POST') {
   174|    return ownerOnlyJson({ success: false, message: 'Method not allowed.', deploymentMarker: DEPLOYMENT_MARKER }, 405);
   175|  }
   176|
   177|  let body: Record<string, unknown> = {};
   178|  try {
   179|    body = (await request.json().catch(() => ({}))) as Record<string, unknown>;
   180|  } catch {
   181|    body = {};
   182|  }
   183|  const email = sanitizeEmail(body.email);
   184|
   185|  if (!isValidEmail(email)) {
   186|    const failure: OwnerSessionFailure = {
   187|      success: false,
   188|      message: 'A valid owner email is required.',
   189|      rootCause: 'missing_or_invalid_email',
   190|      deploymentMarker: DEPLOYMENT_MARKER,
   191|      timestamp: nowIso(),
   192|    };
   193|    return ownerOnlyJson(failure, 400);
   194|  }
   195|
   196|  const allowlist = getIVXOwnerEmailAllowlist();
   197|  if (!allowlist.includes(email)) {
   198|    const failure: OwnerSessionFailure = {
   199|      success: false,
   200|      message: 'This email is not on the owner allowlist. Owner login is restricted to the configured owner.',
   201|      rootCause: 'email_not_allowlisted',
   202|      deploymentMarker: DEPLOYMENT_MARKER,
   203|      timestamp: nowIso(),
   204|    };
   205|    return ownerOnlyJson(failure, 403);
   206|  }
   207|
   208|  const ownerPassword = readEnv('IVX_OWNER_PASSWORD');
   209|  if (!ownerPassword) {
   210|    const failure: OwnerSessionFailure = {
   211|      success: false,
   212|      message: 'IVX_OWNER_PASSWORD is not configured on the backend. Set it in the Render environment to enable passwordless owner login.',
   213|      rootCause: 'owner_password_not_configured',
   214|      deploymentMarker: DEPLOYMENT_MARKER,
   215|      timestamp: nowIso(),
   216|    };
   217|    return ownerOnlyJson(failure, 500);
   218|  }
   219|
   220|  const supabaseUrl = resolveSupabaseUrl();
   221|  if (!supabaseUrl) {
   222|    const failure: OwnerSessionFailure = {
   223|      success: false,
   224|      message: 'Supabase URL is not configured on the backend.',
   225|      rootCause: 'supabase_url_not_configured',
   226|      deploymentMarker: DEPLOYMENT_MARKER,
   227|      timestamp: nowIso(),
   228|    };
   229|    return ownerOnlyJson(failure, 500);
   230|  }
   231|
   232|  let adminClient: SupabaseClient;
   233|  try {
   234|    adminClient = createAdminClient();
