   798|    .upsert(basePayload, {
   799|      onConflict: 'id',
   800|      ignoreDuplicates: false,
   801|    });
   802|
   803|  if (error) {
   804|    const message = error.message || '';
   805|    const lower = message.toLowerCase();
   806|    // Defensive: if the production schema is missing another optional column
   807|    // (e.g. country/avatar) drop it and retry once with the minimum owner row.
   808|    const missingColumnMatch = lower.match(/column "?([a-z_]+)"? .*does not exist/);
   809|    const missingColumn = missingColumnMatch?.[1];
   810|    if (missingColumn && missingColumn in basePayload) {
   811|      console.log('[IVXOwnerRegistration] Owner profile upsert dropping missing column and retrying:', missingColumn);
   812|      const retryPayload = { ...basePayload };
   813|      delete retryPayload[missingColumn];
   814|      const retry = await client
   815|        .from('profiles')
   816|        .upsert(retryPayload, { onConflict: 'id', ignoreDuplicates: false });
